def get_transfer_code(sn, p):
    """
    第一步：獲取轉贈驗證碼 (Captcha)
    """
    url = f"https://ibongift.com/TicketInfo/GiftShop2RetunAccount/{sn}"
    headers = {
        "Authorization": f"Bearer {IBON_AUTH_TOKEN}",
        "Content-Type": "application/x-www-form-urlencoded",
        "User-Agent": "Mozilla/5.0 (iPhone; CPU iPhone OS 16_2_1 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Mobile/15E148"
    }
    data = {
        "sn": sn,
        "p": p,
        "platform": "ClientTicket"
    }
    
    try:
        print(f"[*] 正在請求轉贈資訊 (SN: {sn})...")
        response = requests.post(url, headers=headers, data=data)
        response.raise_for_status()
        res_json = response.json()
        
        if res_json.get("Code") == 200:
            code = res_json.get("Data", {}).get("code")
            print(f"[+] 成功獲取驗證碼: {code}")
            return code
        else:
            print(f"[-] 獲取失敗: {res_json}")
            return None
    except Exception as e:
        print(f"[!] 請求出錯: {e}")
        return None

def execute_transfer(card_sn_encrypted, captcha):
    """
    第二步：執行轉贈
    """
    url = "https://frontendapi.azurefd.net/api/ECoupon/ECouponTransfer"
    headers = {
        "Authorization": f"Bearer {TRANSFER_AUTH_TOKEN}",
        "Content-Type": "application/json",
        "User-Agent": "Mozilla/5.0 (iPhone; CPU iPhone OS 18_7 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Mobile/15E148",
        "Origin": "https://711gift.ibon.com.tw",
        "Referer": "https://711gift.ibon.com.tw/"
    }
    payload = {
        "CardSN": card_sn_encrypted,
        "Captcha": captcha
    }
    
    try:
        print(f"[*] 正在執行轉贈 (Captcha: {captcha})...")
        response = requests.post(url, headers=headers, json=payload)
        response.raise_for_status()
        res_json = response.json()
        
        # 根據回應判斷是否成功
        if res_json.get("StatusCode") == 0:
            print("[+] 轉贈完成！")
            print(f"    結果訊息: {res_json.get('Message')}")
            print(f"    票券名稱: {res_json.get('Entries', {}).get('ProductName')}")
        else:
            print(f"[-] 轉贈失敗: {res_json}")
    except Exception as e:
        print(f"[!] 轉贈請求出錯: {e}")

